    if (nums.length <= 1) {
        return 0;
    }

    // total_cost tracks S'_i, the minimum cumulative increase required at the current index i.
    // S'_0 = 0
    let total_cost = 0;

    // We iterate through adjacent pairs (i, i+1) from i=0 to i=n-2.
    // In iteration i, we calculate the required cumulative increase S'_{i+1}.
    for (let i = 0; i < nums.length - 1; i++) {
        // We require B[i] <= B[i+1].
        // This means S_{i+1} - S_i >= nums[i] - nums[i+1].

        const required_jump = nums[i] - nums[i+1];

        if (required_jump > 0) {
            // If nums[i] > nums[i+1], we need S_{i+1} to be at least S_i + required_jump.
            // We accumulate this required jump to find the minimum S'_{i+1}.
            total_cost += required_jump;
        }
        // If required_jump <= 0, S'_{i+1} = S'_i, so total_cost remains unchanged.
    }

    // The final total_cost is S'_{n-1}, which is the minimum required sum of x's.
    return total_cost;
